import numpy as np
import itertools


#GENERATED BY GEMINI 3.1

def make_nd_checkerboard(n_samples=2000, grid_shape=(4, 4), box_size=1.0, noise=0.05, random_state=None):
    """
    Generates an N-dimensional checkerboard dataset.
    
    Parameters:
    - n_samples: Number of data points to generate.
    - grid_shape: Tuple specifying the number of boxes along each dimension 
                  (e.g., (5, 3) for 2D, (5, 5, 1) or (3, 3, 3) for 3D).
    - box_size: Side length of each individual box.
    - noise: Standard deviation of Gaussian noise added to the points.
    - random_state: Seed for reproducibility.
    
    Returns:
    - X: Array of shape (n_samples, len(grid_shape)) containing the N-D coordinates.
    - c: Array of shape (n_samples,) containing the box index.
    """
    if random_state is not None:
        np.random.seed(random_state)

    D = len(grid_shape)

    # 1. Generate all possible grid indices for the given shape
    # e.g., (2, 2) -> [[0,0], [0,1], [1,0], [1,1]]
    ranges = [range(dim) for dim in grid_shape]
    all_indices = np.array(list(itertools.product(*ranges)))

    # 2. Filter for valid boxes where the sum of indices is even
    valid_mask = np.sum(all_indices, axis=1) % 2 == 0
    valid_boxes = all_indices[valid_mask]

    # 3. Randomly assign each sample to a valid box
    box_indices = np.random.choice(len(valid_boxes), size=n_samples)
    chosen_boxes = valid_boxes[box_indices]

    # 4. Sample uniformly within the chosen boxes
    offsets = np.random.uniform(0, 1, size=(n_samples, D))
    X = (chosen_boxes + offsets) * box_size

    # 5. Center the entire grid around the origin
    center_offset = (np.array(grid_shape) * box_size) / 2.0
    X -= center_offset

    # 6. Add Gaussian noise
    if noise > 0.0:
        X += np.random.normal(0, noise, X.shape)

    return X, box_indices